sealed class JsonValueException: kotlin.Exception() {

    class Invalid(

        val `reason`: kotlin.String
        ) : JsonValueException() {
        override val message
            get() = "reason=${ `reason` }"
    }





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<JsonValueException> {
        override fun lift(error_buf: RustBuffer.ByValue): JsonValueException = FfiConverterTypeJsonValueError.lift(error_buf)
    }


}

/**
 * @suppress
 */
public object FfiConverterTypeJsonValueError : FfiConverterRustBuffer<JsonValueException> {
    override fun read(buf: ByteBuffer): JsonValueException {


        return when(buf.getInt()) {
            1 -> JsonValueException.Invalid(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: JsonValueException): ULong {
        return when(value) {
            is JsonValueException.Invalid -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: JsonValueException, buf: ByteBuffer) {
        when(value) {
            is JsonValueException.Invalid -> {
                buf.putInt(1)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




